        this(
    uniffiRustCallWithError(NuruNuruFfiException) { _status ->
    UniffiLib.INSTANCE.uniffi_uniffi_nurunuru_fn_constructor_nurunuruclient_new(
        FfiConverterString.lower(`secretKeyHex`),_status)
}
    )

