/**
 * @suppress
 */
public object FfiConverterTypeNuruNuruClient: FfiConverter<NuruNuruClient, Pointer> {

    override fun lower(value: NuruNuruClient): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): NuruNuruClient {
        return NuruNuruClient(value)
    }

    override fun read(buf: ByteBuffer): NuruNuruClient {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: NuruNuruClient) = 8UL

    override fun write(value: NuruNuruClient, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



